                    let lhs_i32 = builder.ins().fcvt_to_sint_sat(types::I32, lhs);
                    let rhs_i32 = builder.ins().fcvt_to_sint_sat(types::I32, rhs);
                    let result = builder.ins().bxor(lhs_i32, rhs_i32);
                    builder.ins().fcvt_from_sint(types::F64, result)
