                                        builder.switch_to_block(loop_body);
                                        let idx = builder.use_var(idx_var);
                                        let get_call = builder.ins().call(get_ref, &[spread_arr_ptr, idx]);
                                        let elem_val = builder.inst_results(get_call)[0];

